import { createContext, useContext, useState, useEffect } from 'react';
import { notify } from './notification.helpers';

interface NotificationContextValue {
  notify: (props: Parameters<typeof notify>[1]) => Promise<void>;
}

const NotificationContext = createContext<NotificationContextValue | null>(null);

const useNotification = (): NotificationContextValue => {
  const notificationElem = useContext(NotificationContext);

  if (!notificationElem) {
    throw new Error('useNotification must be used within a NotificationContext');
  }

  const notify = async (props: Parameters<typeof notify>[1]) => {
    try {
      await notify(notificationElem, props);
    } catch (error) {
      console.error(error);
    }
  };

  return { notify };
};

export { NotificationContext, useNotification };
